#include<bits/stdc++.h>
using namespace std;
#define endl '\n'
const int maxn=1e2+5,kd[][2]= {1,0,-1,0,0,1,0,-1},inf=0x7fffffff;

int m,n,a[maxn][maxn],d[maxn][maxn][5],ans;
struct node {
	int x,y,c;
};//c-1无 0 红 1黄 2 染红 3 染黄
vector<node>q[maxn*maxn*2];

int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);

	cin>>m>>n;
	fill(d[0][0],d[2+m][0],inf);
	fill(a[0],a[2+m],-1);//??
	for(int i=1,x,y,c; i<=n; i++) {
		cin>>x>>y>>c;
		a[x][y]=c;//?  a[y][x]=c;
	}
	q[0].push_back({1,1,a[1][1]}) ;
	for(int i=0; q[i].size()||q[i+1].size(); i++) { //?
		for(int j=0; j<q[i].size(); j++) {
			auto p=q[i][j];
			if(d[p.x][p.y][p.c]==inf) {
				d[p.x][p.y][p.c]=i;
				for(int k=0; k<4; k++) {
					int dx=p.x+kd[k][0],dy=p.y+kd[k][1];
					if(dx>=1&&dx<=m && dy>=1&&dy<=m) {
						if(a[dx][dy]>=0) {
							if(p.c%2==a[dx][dy]) {
								q[i].push_back({dx,dy,a[dx][dy]});//0
							} else {
								q[i+1].push_back({dx,dy,a[dx][dy]});//1
							}
						} //如果新点没有颜色
						if(p.c<2 && a[dx][dy]==-1) { //
							q[i+2].push_back({dx,dy,p.c+2});//2
						}
					}
				}
			}
		}
	}
	ans=min({d[m][m][0],d[m][m][1],d[m][m][2],d[m][m][3]});
	if(ans!=inf) cout<<ans;
	else cout<<-1;
	return 0;
}
